detailed_optimizations.code_changes:
在 kernel 前构造 AT（仅需要 A 的下三角转置后变为上三角的连续行访问），然后在 kernel 中用 AT[i][k] 替代 A[k][i]：

// allocate AT[M][M]
for (int k=0;k<m;k++)
  for (int i=0;i<k;i++) // original uses k>i
    AT[i][k] = A[k][i];

// kernel
for (int i=0;i<_PB_M;i++)
  for (int j=0;j<_PB_N;j++) {
    DATA_TYPE sum = B[i][j];
    for (int k=i+1;k<_PB_M;k++)
      sum += AT[i][k] * B[k][j];
    B[i][j] = alpha * sum;
  }

并建议 AT 使用对齐分配（posix_memalign / aligned_alloc）并加 restrict：
void kernel_trmm(..., DATA_TYPE (*restrict AT)[M], DATA_TYPE (*restrict B)[N])

将 (j) 循环分块，并把 B[i][j] 先读入寄存器 sum，最后一次性写回：

const int BJ = 64/sizeof(DATA_TYPE); // 例如 double 时 BJ=8
for (int i=0;i<_PB_M;i++) {
  for (int jb=0;jb<_PB_N;jb+=BJ) {
    int jend = (jb+BJ<_PB_N)?(jb+BJ):_PB_N;
    for (int j=jb;j<jend;j++) {
      DATA_TYPE sum = B[i][j];
      for (int k=i+1;k<_PB_M;k++)
        sum += A[k][i] * B[k][j];
      B[i][j] = alpha * sum;
    }
  }
}

进一步可对 j 做 4/8 路展开以促使编译器生成 SIMD（见下一条）。

重排循环次序为 i 外层、k 中层、j 内层（j 连续，利于 SIMD），并用临时累加到 B[i][j]：

for (int i=0;i<_PB_M;i++) {
  // 先缩放 B[i][:]
  #pragma omp simd
  for (int j=0;j<_PB_N;j++) B[i][j] *= alpha;

  for (int k=i+1;k<_PB_M;k++) {
    DATA_TYPE aik = alpha * A[k][i];
    #pragma omp simd
    for (int j=0;j<_PB_N;j++)
      B[i][j] += aik * B[k][j];
  }
}

注意：该变换保持语义（原式 B[i][j]=alpha*(B[i][j]+sum A[k][i]*B[k][j])；这里先 B[i]*=alpha，再累加 alpha*A[k][i]*B[k]）。建议加编译选项 -O3 -march=native，并确保 B 行对齐（PolyBench 通常已对齐，但可显式）。

i 维不同线程写不同的 B[i][:]，读 B[k][:] 共享只读，天然无写冲突：

#pragma omp parallel for schedule(static)
for (int i=0;i<_PB_M;i++) {
  for (int j=0;j<_PB_N;j++) B[i][j] *= alpha;
  for (int k=i+1;k<_PB_M;k++) {
    DATA_TYPE aik = alpha * A[k][i];
    #pragma omp simd
    for (int j=0;j<_PB_N;j++) B[i][j] += aik * B[k][j];
  }
}

并建议初始化 B 时也并行以实现 NUMA first-touch：
#pragma omp parallel for collapse(2) schedule(static)
for(i=0;i<m;i++) for(j=0;j<n;j++) B[i][j]=...;

1) 给数组指针加 restrict（或在函数签名中使用 __restrict__）并确保对齐（posix_memalign/PolyBench 对齐宏）。
2) 将二维下标提升为行指针，减少乘法寻址。
3) 加 OpenMP 并行与 SIMD 指令提示。
示例（核心片段）：
```c
void kernel_fdtd_2d(...,
  DATA_TYPE (* __restrict__ ex)[NY],
  DATA_TYPE (* __restrict__ ey)[NY],
  DATA_TYPE (* __restrict__ hz)[NY],
  DATA_TYPE * __restrict__ _fict_)
{
  for (int t=0; t<_PB_TMAX; t++) {
    #pragma omp parallel for simd
    for (int j=0; j<_PB_NY; j++) ey[0][j] = _fict_[t];

    #pragma omp parallel for collapse(2)
    for (int i=1; i<_PB_NX; i++) {
      DATA_TYPE * __restrict__ eyi = ey[i];
      DATA_TYPE * __restrict__ hzi = hz[i];
      DATA_TYPE * __restrict__ hzim1 = hz[i-1];
      #pragma omp simd
      for (int j=0; j<_PB_NY; j++) {
        eyi[j] = eyi[j] - (DATA_TYPE)0.5 * (hzi[j] - hzim1[j]);
      }
    }
    ...
  }
}
```

1) 将 j=1..NY-1 主体与 j=0 边界分离（当前已从 1 开始，保持）。
2) 行指针提升 + #pragma omp simd。
3) 若编译器支持且确认写不再被读取，可尝试 non-temporal store（谨慎：ex 在同一 t 的 hz 更新会读取 ex[i][j] 与 ex[i][j+1]，因此对 ex 的写通常会很快被读取，不适合流式写）。
示例：
```c
#pragma omp parallel for collapse(2)
for (int i=0; i<_PB_NX; i++) {
  DATA_TYPE * __restrict__ exi = ex[i];
  DATA_TYPE * __restrict__ hzi = hz[i];
  #pragma omp simd
  for (int j=1; j<_PB_NY; j++) {
    exi[j] = exi[j] - (DATA_TYPE)0.5 * (hzi[j] - hzi[j-1]);
  }
}
```

关键点：hz 更新读取 ex[i][j], ex[i][j+1], ey[i][j], ey[i+1][j]，这些数据刚在同一 t 的前两段循环写入。若数组很大，写入后很快被逐出缓存，会导致 hz 阶段再次从内存读回，带宽压力翻倍。

做法 A（推荐，通用 CPU）：对 i/j 做块划分，使 ex/ey 的“刚写数据”在缓存中被 hz 阶段消费。
```c
const int BI=32, BJ=256; // 需按 L2/L3 与 NY 调参
for (int t=0; t<_PB_TMAX; t++) {
  #pragma omp parallel for
  for (int j=0; j<_PB_NY; j++) ey[0][j]=_fict_[t];

  for (int ii=1; ii<_PB_NX; ii+=BI) {
    int iend = (ii+BI<_PB_NX)? ii+BI : _PB_NX;
    for (int jj=0; jj<_PB_NY; jj+=BJ) {
      int jend = (jj+BJ<_PB_NY)? jj+BJ : _PB_NY;

      // ey tile
      #pragma omp parallel for collapse(2)
      for (int i=ii; i<iend; i++) {
        DATA_TYPE *eyi=ey[i]; DATA_TYPE *hzi=hz[i]; DATA_TYPE *hzim1=hz[i-1];
        #pragma omp simd
        for (int j=jj; j<jend; j++) eyi[j] -= (DATA_TYPE)0.5*(hzi[j]-hzim1[j]);
      }

      // ex tile (note j starts at 1)
      #pragma omp parallel for collapse(2)
      for (int i=ii-1; i<iend; i++) { // include ii-1 row because hz uses ey[i+1]
        if (i<0 || i>=_PB_NX) continue;
        DATA_TYPE *exi=ex[i]; DATA_TYPE *hzi=hz[i];
        int js = (jj==0)? 1 : jj;
        #pragma omp simd
        for (int j=js; j<jend; j++) exi[j] -= (DATA_TYPE)0.5*(hzi[j]-hzi[j-1]);
      }

      // hz tile consumes fresh ex/ey
      #pragma omp parallel for collapse(2)
      for (int i=ii-1; i<iend-1; i++) {
        if (i<0) continue;
        DATA_TYPE *hzi=hz[i]; DATA_TYPE *exi=ex[i]; DATA_TYPE *eyi=ey[i]; DATA_TYPE *eyip1=ey[i+1];
        int je = (jend==_PB_NY)? _PB_NY-1 : jend;
        #pragma omp simd
        for (int j=jj; j<je; j++) {
          hzi[j] -= (DATA_TYPE)0.7 * ( (exi[j+1]-exi[j]) + (eyip1[j]-eyi[j]) );
        }
      }
    }
  }
}
```
做法 B（更激进）：在小 tile 内融合 ex/ey/hz 的计算顺序以最大化 L1/L2 复用，但要小心边界与依赖（hz 需要 ex 的 j+1 与 ey 的 i+1）。

将表达式改写为一次性读取 center 与 6 个邻居，避免对 A[i][j][k] 重复读取 3 次；并用 restrict/指针线性化帮助编译器。示例（A->B 一段）：

// 线性化访问（可选）
DATA_TYPE * __restrict a = &A[0][0][0];
DATA_TYPE * __restrict b = &B[0][0][0];
const int NN = n*n;
const DATA_TYPE c = (DATA_TYPE)0.125;

for (i=1;i<n-1;i++)
  for (j=1;j<n-1;j++) {
    int base = i*NN + j*n;
    #pragma omp simd
    for (k=1;k<n-1;k++) {
      int idx = base + k;
      DATA_TYPE center = a[idx];
      DATA_TYPE lap = (a[idx+NN] + a[idx-NN] + a[idx+n] + a[idx-n] + a[idx+1] + a[idx-1] - (DATA_TYPE)6.0*center);
      b[idx] = center + c*lap;
    }
  }

同理对 B->A 段做相同改写。并建议编译选项：-O3 -ffast-math -march=native（或对应平台）以增强 FMA/向量化。

对 i/j/k 做分块，保证一个 tile 的 3D slab（含 halo）能驻留在 L2/LLC，减少 i/j 方向跨平面访问带来的 cache miss。示例（仅示意）：

const int Bi=16, Bj=16, Bk=128; // 需按 L2/LLC 与数据类型调参
for (t=1;t<=TSTEPS;t++) {
  for (int ii=1; ii<n-1; ii+=Bi)
    for (int jj=1; jj<n-1; jj+=Bj)
      for (int kk=1; kk<n-1; kk+=Bk)
        for (i=ii; i<min(ii+Bi,n-1); i++)
          for (j=jj; j<min(jj+Bj,n-1); j++) {
            int base=i*NN+j*n;
            #pragma omp simd
            for (k=kk; k<min(kk+Bk,n-1); k++) { /* stencil */ }
          }
  // B->A 同样分块
}

要点：保持 k 为最内层（连续），并让 (Bi,Bj,Bk) 使得 (Bi*Bj*(Bk+2 halo))*sizeof(DATA_TYPE) 适配缓存。

并行化 i/j 维（避免对 k 维并行导致短循环开销），并确保 init_array 也并行以 first-touch：

#pragma omp parallel for collapse(2) schedule(static)
for (i=1;i<n-1;i++)
  for (j=1;j<n-1;j++)
    for (k=1;k<n-1;k++) { /* compute */ }

// init_array 同样加 parallel for collapse(2/3)

运行时建议：OMP_PROC_BIND=close, OMP_PLACES=cores；NUMA 系统用 numactl --interleave=all 或按 socket 绑定。

将 t 维与空间维一起分块，在一个空间 tile 内连续推进多个时间步，使数据在缓存/共享内存中复用，显著降低每步全域读写。实现方式包括：diamond tiling、wavefront skewing（对 i/j/k 做 skew 以满足依赖）。

伪代码（概念）：
for (tt=1; tt<=TSTEPS; tt+=Tt)
  for (tile over i,j,k with skew)
    for (t=tt; t<tt+Tt; t++)
      update within tile respecting dependencies

该优化复杂但对 stencil 通常收益最大。

方案A(推荐，改算法语义为Jacobi，数值略不同但常用于性能基准)：
1) 增加第二个数组B；每个t步从A读写B，然后swap。
```cpp
POLYBENCH_2D_ARRAY_DECL(B, DATA_TYPE, N, N, n, n);
for (t=0; t<_PB_TSTEPS; t++) {
  for (i=1; i<=_PB_N-2; i++)
    for (j=1; j<=_PB_N-2; j++)
      B[i][j] = (A[i-1][j-1]+A[i-1][j]+A[i-1][j+1]
               +A[i][j-1]  +A[i][j]  +A[i][j+1]
               +A[i+1][j-1]+A[i+1][j]+A[i+1][j+1]) * (DATA_TYPE)(1.0/9.0);
  // swap pointers (or copy boundaries)
  auto tmp=A; A=B; B=tmp;
}
```
方案B(保持Seidel语义)：red-black 着色，两相更新可并行：
```cpp
for (t=0; t<_PB_TSTEPS; t++) {
  // red
  #pragma omp parallel for collapse(2)
  for (i=1;i<=_PB_N-2;i++)
    for (j=1;j<=_PB_N-2;j++) if(((i+j)&1)==0) update(A,i,j);
  // black
  #pragma omp parallel for collapse(2)
  for (i=1;i<=_PB_N-2;i++)
    for (j=1;j<=_PB_N-2;j++) if(((i+j)&1)==1) update(A,i,j);
}
```
并对(i,j)做tile(例如Ti=32,Tj=256或按cache调参)：
```cpp
for (ii=1; ii<=_PB_N-2; ii+=Ti)
  for (jj=1; jj<=_PB_N-2; jj+=Tj)
    for (i=ii; i<min(ii+Ti,_PB_N-1); i++)
      for (j=jj; j<min(jj+Tj,_PB_N-1); j++) ...
```

1) 将除法替换为常量乘法：
```cpp
const DATA_TYPE inv9 = (DATA_TYPE)(1.0/9.0);
...
A[i][j] = sum * inv9;
```
2) 若允许改为Jacobi或red-black后，可对内层j向量化：
- 使用指针行缓存，减少二维索引开销并帮助编译器：
```cpp
DATA_TYPE* __restrict Ai   = &A[i][0];
DATA_TYPE* __restrict Aim1 = &A[i-1][0];
DATA_TYPE* __restrict Aip1 = &A[i+1][0];
#pragma omp simd
for (j=1; j<=_PB_N-2; j++) {
  DATA_TYPE sum = Aim1[j-1]+Aim1[j]+Aim1[j+1]
                +Ai[j-1]  +Ai[j]  +Ai[j+1]
                +Aip1[j-1]+Aip1[j]+Aip1[j+1];
  Ai[j] = sum * inv9;
}
```
3) 确保A按cache line对齐(PolyBench通常已做，但可检查)；编译选项：`-O3 -march=native -ffast-math`(若允许)；OpenMP：`-fopenmp`。
